        ```code
        #include <bits/stdc++.h>

using namespace std;

ifstream in("crypto.in");
ofstream out("crypto.out");

void print_retea(vector<pair<long long, long long>> retea) {
  for (long long i = 0; i < retea.size(); i++) {
    cout << retea[i].first << " " << retea[i].second << endl;
  }
}

// functie de comparatie ce este folosita la sortarea datelor de intrare,
// crescator in functie de putere si pret (in caz de == la putere)
bool compare(pair<long long, long long> p1, pair<long long, long long> p2) {
  if (p1.first < p2.first)
    return 1;
  if (p1.first > p2.first)
    return 0;
  if (p1.second < p2.second)
    return 1;
  if (p1.second < p2.second)
    return 0;
  return 0;
}

int main() {
  long long n, b, p, u;
  in >> n >> b;
  // calculatoarele (putere, pret) sunt salvate in memorie ca si un vector de
  // perechi
  vector<pair<long long, long long>> retea;
  for (long long i = 0; i < n; i++) {
    in >> p >> u;
    retea.push_back(make_pair(p, u));
  }

  // reteaua este sortata folosind std::sort impreuna
  // cu functia compare (as I read online, std::sort is quicker than quicksort)
  sort(retea.begin(), retea.end(), compare);
  long long level = 0;
  long long mining_rate = retea[0].first;
  long long price = 0;

  /*
  cat timp mai sunt bani se stabilesc urmatoarele:
      - cate elemente au acelasi nivel de putere de minare(cel mai mic)
      - se verifica daca nivelul acestora poate fi egalat cu urmatorul
  cel mai slab calculator(daca sunt destui bani) -> si daca da se face asta &
  repeat
      - daca nu se poate ridica nivelul, se calculeaza cate nivele se pot
  upgrada acele calculatoare, se cumpara nivelele si se opreste programul
  */
  while (b > 0) {
    if (retea[0].second > b)
      break;

    if (retea[0].first < retea[1].first) {
      if ((retea[1].first - retea[0].first) * retea[0].second < b) {
        b -= (retea[1].first - retea[0].first) * retea[0].second;
        retea[0].first = retea[1].first;
        mining_rate = retea[0].first;
      } else {
        long long aux = b / retea[0].second;
        b -= aux * retea[0].second;
        retea[0].first += aux;
        mining_rate = retea[0].first;
        break;
      }
    } else {
      while (level < retea.size()) {
        if (mining_rate == retea[level].first) {
          price += retea[level].second;
          level++;
        } else {
          break;
        }
      }
      if (price > b) {
        break;
      } else {
        if (level < retea.size()) {
          long long aux = retea[level].first - mining_rate;
          if (aux * price > b) {
            aux = b / price;
            mining_rate += aux;
            break;
          } else {
            b -= (aux * price);
            mining_rate += aux;
          }
        } else {
          long long aux = b / price;
          mining_rate += aux;
          break;
        }
      }
    }
  }

  out << mining_rate << endl;
}

        ```

