        ```code
        #include <bits/stdc++.h>
#include <iostream>
#include <fstream>
#include <vector>
using namespace std;

// Functie utilizata la sortarea vectorului de perechi
bool comparator(pair<int, int> a, pair<int, int> b) {
	return a.first < b.first;
}

// Functie in care se determina numarul maxim de criptomonede
int solve(int b, vector<pair<int, int>> computers, int n) {
	/*
	ant_cost va contine costul de upgrade pana la numarul maxim de criptomonede
	*/
	int ant_cost = 0, ant = computers[0].first;
	/*
	cost_pred va retine costul de upgrade total pentru upgradarea
	calculatoarelor anterioare cu o unitate
	*/
	int cost_pred = computers[0].second;
	int i = 0;
	while (i < n) {
		i++;
		/*
		Daca actualul calculator poate produce acelasi nr de criptomonede ca
		cel anterior, se actualizeaza doar cost_pred
		*/
		if (computers[i].first == ant) {
			cost_pred += computers[i].second;
			continue;
		}
		/*
		Altfel, se va incerca upgradarea calculatoarelor anterioare la numarul
		calculatorului actual
		*/
		if (computers[i].first > ant) {
			int diff = computers[i].first - ant;
			/*
			current_crypto va reprezenta valaoarea pana la care se pot upgrada
			calculatoarele de pana acum
			*/
			int current_crypto = (b - ant_cost) / cost_pred;
			/*
			Daca este o valoare mai mica decat diferenta dintre valoarea
			calculatorului actual si numarul de criptomonede obtinute pana acum
			*/
			if (current_crypto < diff) {
				ant += current_crypto;
				ant_cost = b;
				break;
			}
			/*
			Altfel, calculatoarele se vor upgrada doar pana la numarul de
			criptomonede pe care le poate procesa calculatorul curent
			*/
			if (current_crypto > diff) {
				ant = computers[i].first;
				ant_cost += diff * cost_pred;
			}
		}
		cost_pred += computers[i].second;
	}
	/*
	Daca se mai pot upgrada calculatoarele, se creste ant pana cand se
	depaseste bugetul
	*/
	ant += (b - ant_cost) / cost_pred;
	return ant;
}

int main() {
	vector<pair<int, int>> computers;
	ifstream input;
	input.open("crypto.in");
	ofstream output;
	output.open("crypto.out");
	int n, b, i;
	input >> n >> b;
	for (i = 0; i < n; i++) {
		pair<int, int> p;
		input >> p.first >> p.second;
		computers.push_back(p);
	}
	/*
	Se sorteaza calculatoarele in functie de numarul de criptomonede pe care
	le pot mina la inceput
	*/
	sort(computers.begin(), computers.end(), comparator);
	output << solve(b, computers, n);
	input.close();
	output.close();
	return 0;
}

