using namespace std;

class Task {
 public:
    void solve() {
        read_input();
        print_output(get_result());
    }

 private:
    int N, B, L;              // N = number of total actions
                              // B = maximum available money
                              // L = maximum loss
    vector<int> current_val;  // current prices
    vector<int> min_val;      // minimum prices
    vector<int> max_val;      // maximum prices

    void read_input() {
        ifstream fin("stocks.in");
        fin >> N >> B >> L;

        // initialise unused values
        current_val.push_back(-1);
        min_val.push_back(-1);
        max_val.push_back(-1);

        // read data
        for (int i = 1, current, min, max; i<= N; i++) {
            fin >> current >> min >> max;
            current_val.push_back(current);
            min_val.push_back(min);
            max_val.push_back(max);
        }

        fin.close();
    }

    int get_result() {
        // initialise tridimensional vector (number of available actions,
        //                                  current money, current loss)
        vector<vector<vector<int>>> dp(N + 1,
                vector<vector<int>>(B + 1, vector <int>(L + 1, 0)));

        for (int i = 1 ; i <= N; i++) {
            for (int j = 0; j <= B; j++) {
                for (int k = 0; k <= L; k++) {
                    // i don't buy the action
                    dp[i][j][k] = dp[i - 1][j][k];

                    // compute potential loss and profit
                    int loss = current_val[i] - min_val[i];
                    int profit = max_val[i] - current_val[i];
                    int price = current_val[i];

                    // check if there is money to buy the action and
                    // if the loss isn't too big
                    if (j - price >= 0 && k - loss >= 0) {
                        // compute profit if i buy the action
                        int sol_aux = dp[i - 1][j - price][k - loss] + profit;

                        // chose the largest profit
                        dp[i][j][k] = max(dp[i][j][k], sol_aux);
                    }
                }
            }
        }

        return dp[N][B][L];
    }

    void print_output(int result) {
        ofstream fout("stocks.out");
        fout << result << endl;
        fout.close();
    }
};

int main() {
    // allocate a Task object on heap
    // call solve method (read, get_result, write)
    // destroy the object and free the memory

    auto* task = new (std::nothrow) Task{};
    if (!task) {
        std::cerr << "new failed: What are you doing? Throw your PC!\n";
        return -1;
    }
    task->solve();
    delete task;
    return 0;
}

