				.collect(Collectors.toCollection(ArrayList::new));

		int i = 0;

		ArrayList<Integer> prefix = new ArrayList<>();
		ArrayList<Integer> sufix = new ArrayList<>();

		int minPeak = Collections.min(peaks);
		int index = peaks.indexOf(minPeak);
		long hours = 0;

		if (index == 0) {
			prefix.add(peaks.get(0));
			prefix.add(peaks.get(1));
			sufix.addAll(peaks.subList(2, peaks.size() - 1));
			hours += getPrefixHours(prefix, hours, prefix.size() - 1);

		} else if (index == peaks.size() - 1) {
			prefix.addAll(peaks.subList(0, index - 1));
			sufix.add(peaks.get(index - 1));
			sufix.add(peaks.get(index));

			hours += getPrefixHours(prefix, hours, prefix.size() - 2);
			hours += getSufixHours(sufix, hours);

		} else {
			while (i < index) {
				prefix.add(peaks.get(i));
				i++;
			}
			prefix.add(peaks.get(i));

			while (i < n) {
				sufix.add(peaks.get(i));
				i++;
			}
			hours += getPrefixHours(prefix, hours, prefix.size() - 1);
			int j = 0;
			while (j < sufix.size()) {
				int minSuf = getMin(sufix, j);
				int minPos = sufix.lastIndexOf(minSuf);
				while (j < minPos) {
					int diff = sufix.get(j) - minSuf;
					sufix.set(j, minSuf);
					hours += diff;
					j++;
				}
				j++;
			}
		}
		fw.write(hours + "\n");
		fw.close();
		br.close();
		fr.close();
	}

	private static long getSufixHours(ArrayList<Integer> sufix, long hours) {
		for (int j = 0; j < sufix.size() - 1; j++) {
			int diff = sufix.get(j) - sufix.get(j + 1);
			if (sufix.get(j) > sufix.get(j + 1)) {
				sufix.set(j, sufix.get(j) - (sufix.get(j) - sufix.get(j + 1)));
				hours += diff;
			}
		}
		return hours;
	}

	private static long getPrefixHours(ArrayList<Integer> prefix, long hours, int index) {
		for (int j = 0; j < index; j++) {
			int diff = prefix.get(j + 1) - prefix.get(j);
			if (prefix.get(j) < prefix.get(j + 1)) {
				prefix.set(j + 1, prefix.get(j + 1) - (prefix.get(j + 1) - prefix.get(j)));
				hours += diff;
			}
		}
		return hours;
	}

	public static int getMin(ArrayList<Integer> peaks, int low) {

		ArrayList<Integer> newPeaks = IntStream.range(low, peaks.size())
				.mapToObj(peaks::get).collect(Collectors.toCollection(ArrayList::new));
		return Collections.min(newPeaks);
	}

}

