class disjoint_set {
 public:
    unordered_map<string, string> parent;
    int n;

    explicit disjoint_set(int n) {
        this->n = n;
    }

    void addToSet(string name) {
        parent[name] = name;
    }

    string find(string x) {
        return parent[x] == x ? x : find(parent[x]);
    }

    void Union(string x, string y) {
        string xset = find(x);
        string yset = find(y);

        cout << x << ", " << xset << " | " << y << ", " << yset << '\n';

        if (xset > yset) {
            parent[xset] = yset;
            cout << "xset" << parent[xset] << '\n';
        } else {
            parent[yset] = xset;
            cout << "yset" << parent[yset] << '\n';
        }
    }
};

