int main(int argc, char *args[]) {
    int N, K, count = 0;
    string name;
    string email;
    set<pair<string, string>> pairs;

    /*
     * map of users and their emails'
     * key = name of user
     * value = set of emails
     */
    unordered_map<string, set<string>> user_emails;
    /*
     * map of emails and the first user that appears using it
     * key = email
     * value = first user using the email
     */
    unordered_map<string, string> history;
    /*
     * disjoint set used to store and identify the same users
     */
    disjoint_set ds(count);

    ifstream in_file("adrese.in");
    ofstream out_file("adrese.out");

    in_file >> N;
    /*
     * vector of all users
     */
    vector<string> users(N, "");

    for (int i = 0; i < N; i++) {
        in_file >> name >> K;

        // add the index to the string so the object is different then another
        // person with the same name
        name += to_string(i);

        users.emplace_back(name);
        ds.addToSet(name);

        set<string> emails;
        for (int j = 0; j < K; j++) {
            in_file >> email;

            emails.insert(email);

            // if the emails is already used by another user
            if (history.find(email) != history.end()) {
                // link the two users
                ds.Union(name, history[email]);
            } else {
                history[email] = name;
            }
        }
        user_emails[name] = emails;
        count++;
    }

    // compress users with the same parent (the same user with different names)
    for (auto it = users.begin(); it != users.end(); it++) {
        if (ds.find(*it) != *it) {
            user_emails[ds.find(*it)].insert(user_emails[*it].begin(),
                                                    user_emails[*it].end());
            user_emails.erase(*it);
            count--;
        }
    }

    out_file << count << '\n';

    // convert the unordered map to a vector so it can be sorted
    vector<pair<string, set<string>>> sorted_users(user_emails.begin(),
                                                   user_emails.end());
    sort(sorted_users.begin(), sorted_users.end(), comp);

    for (auto it = sorted_users.begin(); it != sorted_users.end(); it++) {
        string s = it->first;
        // remove the index at the end of the name
        s.erase(remove_if(s.begin(), s.end(), is_decimal), s.end());

        out_file << s << ' ' << it->second.size() << '\n';
        for (auto iter = it->second.begin(); iter != it->second.end(); iter++) {
            out_file << *iter << '\n';
        }
    }

    return 0;
}

