std::ifstream input;
int n, i, j, k;
std::string name, email;

std::unordered_map<std::string, struct data> people;
std::unordered_map<std::string, int> name_count;
std::unordered_map<std::string, std::string> emails;
std::unordered_map<std::string, std::vector<std::string>> adj;

int main(int argc, char *argv[]) {
    // Check if the input file has been given as a command line argument
    if (argc < 1) {
        std::cout << "Wrong syntax! Use: ./adrese [input_file]" << std::endl;
        return 1;
    }

    input.open(argv[1], std::ios::in);
    input >> n;

    for (i = 0; i < n; ++i) {
        input >> name >> k;

        std::string id = "";
        if (name_count.find(name) != name_count.end()) {
            id = name + std::to_string(++name_count[name]);
            people[id] = {name, 0};
        } else {
            id = name;
            people[id] = {name, 0};
            name_count[name]++;
        }

        for (j = 0; j < k; ++j) {
            input >> email;

            // check if the mail already exists
            if (emails.find(email) != emails.end()) {
                // get the other person's id
                std::string ext_id = emails[email];

                if (id == ext_id) {
                    continue;
                }

                // save the lexicographically lower name (pp that id is higher)
                // new_id will be the id that stays in the graph; id will be
                // removed
                std::string name_to_remove = people[id].name;
                if (ext_id > id) {
                    name_to_remove = people[ext_id].name;

                    // ext_id <-> id
                    std::string tmp = id;
                    id = ext_id;
                    ext_id = tmp;
                }

                // update email owner id
                for (std::string& saved_email : adj[id]) {
                    emails[saved_email] = ext_id;
                }

                // add the other emails to the new owner
                adj[ext_id].insert(adj[ext_id].end(), adj[id].begin(),
                    adj[id].end());
                people[ext_id].count = adj[ext_id].size();

                // remove old entries
                adj.erase(id);
                people.erase(id);
                name_count[name_to_remove]--;
                if (name_count[name_to_remove] == 0) {
                    name_count.erase(name_to_remove);
                }

                id = ext_id;
            } else {
