std::vector<std::pair<int32_t, int32_t>> get_positions(
    std::pair<int32_t, int32_t> current, int8_t type) {
    std::vector<std::pair<int32_t, int32_t>> positions;
    int x = current.first;
    int y = current.second;
    switch (type) {
        case 1:
            positions.push_back(std::make_pair(x, y + 1));
            positions.push_back(std::make_pair(x, y - 1));
            positions.push_back(std::make_pair(x + 1, y));
            positions.push_back(std::make_pair(x - 1, y));
            break;
        case 2:
            positions.push_back(std::make_pair(x + 1, y));
            positions.push_back(std::make_pair(x - 1, y));
            break;
        case 3:
            positions.push_back(std::make_pair(x, y + 1));
            positions.push_back(std::make_pair(x, y - 1));
            break;
        default:
            break;
    }
    return positions;
}

// this function returns the minimum distance
// form all positions that are on the border
// of the matrix
int32_t get_min(int** distance, int32_t lines,
                     int32_t columns) {
    int Min = INT32_MAX;

    for (int i = 0; i <= columns; ++i) {
        if (distance[0][i] < Min) {
            Min = distance[0][i];
        }
        if (distance[lines][i] < Min) {
            Min = distance[lines][i];
        }
    }
    for (int i = 0; i <= lines; ++i) {
        if (distance[i][0] < Min) {
            Min = distance[i][0];
        }
        if (distance[i][columns] < Min) {
            Min = distance[i][columns];
        }
    }
    return Min;
}

// this function calculates the minimum distance
// from a position in the matrix to one position
// that is on the border of the matrix
int32_t get_distance(int8_t **matrix, int32_t lines,
                     int32_t columns, int32_t initial_x, int32_t initial_y) {
    std::pair<int32_t, int32_t> current;
    // a 2D array that contains the minimum moves to get
    // to a certain position from the initial one
    int **distance = new int *[lines + 1];
    // a 2D array that contains true if a cell
    // was visited and false otherwise
    bool **visited = new bool *[lines + 1];
    for (int i = 0; i <= lines; ++i) {
        distance[i] = new int[columns + 1];
        visited[i] = new bool[columns + 1];
        for (int j = 0; j <= columns; ++j) {
            distance[i][j] = INT32_MAX;
            visited[i][j] = false;
        }
    }
    // a queue that contains the positions that need to
    // be explored
    std::queue<std::pair<int32_t, int32_t>> pending_positions;

    distance[initial_x][initial_y] = 0;
    visited[initial_x][initial_y] = true;

    pending_positions.push(std::make_pair(initial_x, initial_y));

    while (!pending_positions.empty()) {
        // extracting the first position that wasn't explored yet
        current = pending_positions.front();
        int x = current.first;
        int y = current.second;
        // get the list of possible positions
        std::vector<std::pair<int32_t, int32_t>> next_positions =
                     get_positions(current, matrix[x][y]);
        int size = next_positions.size();
        for (int i = 0; i < size; ++i) {
            int nextx = next_positions[i].first;
            int nexty = next_positions[i].second;
            // check if the position is in the matrix dimensions
            // and if it can be explored
            if (nextx >= 0 && nexty >= 0 &&
                nextx <= lines && nexty <= columns &&
                matrix[nextx][nexty] <= 3 && matrix[nextx][nexty] >= 0) {
                // check if the current path is shorter then the one previously
                // found
                if (distance[nextx][nexty] == INT32_MAX ||
                    distance[nextx][nexty] > distance[x][y] + 1) {
                        // update the shortest path
                        distance[nextx][nexty] = distance[x][y] + 1;
                        // check if the cell was already explored
                        // and if not add the cell to the queue
                        if (!visited[nextx][nexty]) {
                            visited[nextx][nexty] = true;
                            pending_positions.push(next_positions[i]);
                        }
                   }
            }
        }
        pending_positions.pop();
    }
    // get the best path on the border of the matrix
    return get_min(distance, lines, columns);
}

