    long long my_power(long long base, long long exp) {
        int result = 1;
        for (;;) {
            if (exp & 1) {
                result = (1LL *(1LL * result) * (1LL * base)) % mod;
            }
            exp >>= 1;
            if (!exp) {
                break;
            }
            base = (1LL *(1LL * base) * (1LL * base)) % mod;
        }

        return result;
    }

    void read() {
        ifstream fin("crypto.in");
        ofstream fout("crypto.out");
        int n, l;
        string nr_distinct;
        string k, s;
        fin >> n >> l >> k >> s;
        fin.close();
        vector<vector<int>> dp(l, vector<int>(n, 0));
        nr_distinct = cntDistinct(s);
        int count = 0;

        // caz de baza
        if (k[0] == s[0]) {
            dp[0][0] = 1;
        } else if (k[0] == '?') {
            for (int i = 0; i < nr_distinct.size(); i++) {
                if (nr_distinct[i] == s[0]) {
                    dp[0][0] += my_power(nr_distinct.size(), count);
                }
            }
            count++;
        }

        // caz general
        for (int j = 1; j < n; j++) {
            // prima litera
            int i = 0;
            if (k[j] == s[i]) {
                dp[i][j] = (1LL * ((1LL * dp[i][j - 1]) % mod +
                    my_power(nr_distinct.size(), count)) % mod);
            } else if (k[j] == '?') {
                for (int m = 0; m < nr_distinct.size(); m++) {
                    if (nr_distinct[m] == s[i]) {
                        dp[i][j] = 1LL * ((1LL * dp[i][j]) % mod +
                            (1LL * dp[i][j - 1]) % mod +
                            my_power(nr_distinct.size(), count)) % mod;
                    } else {
                        dp[i][j] = 1LL * ((1LL * dp[i][j]) % mod +
                            (1LL * dp[i][j - 1])) % mod;
                    }
                }
                count++;
            } else {
                dp[i][j] = (1LL * dp[i][j - 1]) % mod;
            }
            i++;
            // celelalte litere
            while (i < l) {
                if (k[j] == s[i]) {
                    dp[i][j] = 1LL * (1LL * (1LL * dp[i][j - 1]) % mod +
                        (1LL * dp[i - 1][j - 1]) % mod) % mod;
                } else if (k[j] == '?') {
                    for (int m = 0; m < nr_distinct.size(); m++) {
                    if (nr_distinct[m] == s[i]) {
                            dp[i][j] = 1LL * ((1LL * dp[i][j]) % mod +
                                (1LL * dp[i][j - 1]) % mod +
                                (1LL * dp[i - 1][j - 1]) % mod) % mod;
                        } else {
                            dp[i][j] = 1LL * ((1LL * dp[i][j]) % mod +
                                (1LL * dp[i][j - 1]) % mod) % mod;
                        }
                    }
                } else {
                    dp[i][j] = (1LL * dp[i][j - 1]) % mod;
                }
                i++;
            }
        }
        fout << dp[l - 1][n - 1];
        fout.close();
    }
};

int main() {
    auto* task = new (nothrow) Task();
    if (!task) {
        cerr << "new failed";
        return -1;
    }
    task->solve();
    delete task;
    return 0;
}

