void bfs(int n, int m, vector<vector<char>> matrix,
    pair<int, int> initial_state, 
    vector<vector<int>> &dist, int surfaces_len, int surfaces_count) {
    queue<pair<int, int>> q;
    q.push(initial_state);
    dist[initial_state.first][initial_state.second] = 0;

    while (!q.empty() && surfaces_count < surfaces_len) {
        pair<int, int> current_cell = q.front();
        q.pop();

        int i = current_cell.first;
        int j = current_cell.second;

        // up
        if (i - 1 >= 0 && (dist[i - 1][j] == INT32_MAX) &&
                                            (matrix[i - 1][j] != 'X')) {
            if (matrix[i - 1][j] == 'S') {
                surfaces_count++;
            }
            dist[i - 1][j] = dist[i][j] + 1;
            q.push(pair<int, int>(i - 1, j));
