void backtracking(int n, int k, vector<vector<int>> sets, int pos,
    vector<int> complete_set, int &count) {
    if (pos == k && complete_set.size() == k) {
        int max_sum = 0;
        for (int i = 0; i < n; i++) {
            if (sets[i].size() != 0) {
                min_dist = INT32_MAX;

                back_2(sets[i].size(), 1, vector<int>(),
                    vector<int>(sets[i].size(), 0), sets[i], i);
                max_sum = max(max_sum, min_dist);
