        max_dist = min(max_dist, max_sum);
        return;
    }

    for (int i = pos; i < k; i++) {
        for (int j = 0; j < n; j++) {
            sets[j].push_back(i);
            complete_set.push_back(i);
            backtracking(n, k, sets, i + 1, complete_set, count);
            complete_set.pop_back();
            sets[j].pop_back();
        }
    }
}

