class Badgpt {
	static String str = new String();
	static final int  mod = 1000000007;

	Badgpt(){}

	static long fibonacci(long nr) {
		/*
			In fib we store the base    | 1 |
			cases for Fibonacci =>      | 1 |

			In matrixPower we store the | 1 1 |
			matrix at power n - 1 =>	| 1 0 |
		*/
		long [][]matrix = new long[2][2];

		long []fib = new long[2];
		fib[0] = 1;
		fib[1] = 1;

		long [][]matrixPower = new long[2][2];
		matrixPower[0][0] = 1;
		matrixPower[0][1] = 0;
		matrixPower[1][0] = 0;
		matrixPower[1][1] = 1;

		// pow = curent power to multiply
		long pow = 1;
		// decrease nr to get matrix^(n-1)
		nr--;
		while (nr > 0) {
			// see each bit to know with what matrices powers to multiply
			if ((nr & 1) == 1) {
				matrix[0][0] = 1;
				matrix[0][1] = 1;
				matrix[1][0] = 1;
				matrix[1][1] = 0;
				multiply2x2(matrixPower, power(matrix, pow));
			}
			pow *= 2;
			nr = nr >> 1;
		}
		return result(matrixPower, fib);
	}

	static long result(long [][]matrix, long []fib) {
		// first element of the 1 x 2 matrix formed
		return (((matrix[0][0] * fib[0]) % mod) + ((matrix[0][1] * fib[1]) % mod)) % mod;
	}

	static long[][] power(long [][]matrix, long p) {
		/*
			This works for multiplying matrices with powers of 2.
			In our case, that's what we want only.
		*/
		if (p == 1) {
			return matrix;
		} else {
			return multiplySame(power(matrix, p / 2));
		}
	}

	static long[][] multiplySame(long[][] a) {
		multiply2x2(a, a);
		return a;
	}
	static void multiply2x2(long[][] a, long[][] b) {
		long [][]c = new long[2][2];
		// perform the multiplication of matrices operations
		c[0][0] = (((a[0][0] * b[0][0]) % mod) + ((a[0][1] * b[1][0]) % mod)) % mod;
		c[0][1] = (((a[0][0] * b[0][1]) % mod) + ((a[0][1] * b[1][1]) % mod)) % mod;
		c[1][0] = (((a[1][0] * b[0][0]) % mod) + ((a[1][1] * b[1][0]) % mod)) % mod;
		c[1][1] = (((a[1][0] * b[0][1]) % mod) + ((a[1][1] * b[1][1]) % mod)) % mod;
		// store result in a
		a[0][0] = c[0][0];
		a[0][1] = c[0][1];
		a[1][0] = c[1][0];
		a[1][1] = c[1][1];
	}

	static long taskGpt() {
		long ans = 1;
		long max = -1;
		int arrIndex = 0;
		// find number of times n and u appears
		for (int i = 0; i < str.length(); i++) {
			if (str.charAt(i) == 'n' || str.charAt(i) == 'u') {
				// get each numeric character corresponding to that letter
				String strNum = new String();
				while (++i < str.length() && str.charAt(i) < 'A') {
					strNum += str.charAt(i);
				}
				i--;
				// transform the number into long and multiply
				long nr = Long.valueOf(strNum);
				if (nr >= 2) {
					ans = ((ans % mod) * (fibonacci(nr) % mod)) % mod;
				}

			}
		}
		return ans;
	}

	public static void main(String[] args) {
		try {
			BufferedReader sc = new BufferedReader(new FileReader("badgpt.in"));
			try {
				str = sc.readLine();
			} catch (IOException e) {
				System.out.println(e.getMessage());
			}
			long ans = Badgpt.taskGpt();

			try {
				FileWriter fw = new FileWriter("badgpt.out");
				fw.write(Long.toString(ans) + '\n');
				fw.close();
			} catch (IOException e) {
				System.out.println(e.getMessage());
			}
		} catch (FileNotFoundException e) {
			System.out.println(e.getMessage());
		}
	}
}

