        if(weights[i] > min_cost) {
            min_cost = weights[i];
        }
    }

    while(min_cost < max_cost) {

        mid_cost = (min_cost + max_cost) / 2;

        ferry_count = 1;
        current_weight = 0;

        for(i = 0; i < n; i++) {

        // daca masina nu mai incape pe feribot, se mai adauga unul
        // masina intra pe urmatorul feribot
            if(current_weight + weights[i] > mid_cost) {
