        public static long maxcost(long[] g,int k)
        {
        long a = 0;
        long b = 10000000000000L;
        while (a < b) {
            long m = (a + b) / 2;
            if (check(g, k, m)) {
                b = m;
            } else {
                a = m + 1;
            }
        }
        return b;

    }
    public static boolean check(long[] g, int k, long C) {
        int i = 0;
        int j = 0;
        while (i < g.length) {
            long suma = 0;
            while (i < g.length && suma + g[i] <= C) {
                suma = g[i]+suma;
                i++;
            }
            j++;
            if ( suma == 0 || suma >C || j>k) {
                return false;
            }
        }
        return true;
    }
}

