long max_sum(vector<int>& a, vector<int>& b) {
    long sum = 0;
    for (unsigned long long i = 0; i < a.size(); i++) {
        sum += max(a[i], b[i]);
    }
    return sum;
}

// sortez vectorii a si b in ordine crescatoare si descrescatoare si apelez
// functia de calculare a sumei maxime
int64_t SolveTask1(vector<int>& a, vector<int>& b) {
    std::sort(a.begin(), a.end());
    std::sort(b.begin(), b.end(), std::greater<int>());
    return max_sum(a, b);
}
struct number {
    int value;
    int og_index;
};
int64_t SolveTask2(vector<int>& a, vector<int>& b, int moves) {
    // creez 2 vectori auxiliari in care pun elementele din a si b
    vector<number> c = vector<number>(a.size());
    vector<number> d = vector<number>(b.size());
    for (int i = 0; i < a.size(); i++) {
        c[i].value = a[i];
        c[i].og_index = i;
        d[i].value = b[i];
        d[i].og_index = i;
        if (c[i].value < d[i].value) {
            swap(c[i], d[i]);
        }
    }
    // sortez vectorii c si d in ordine crescatoare si descrescatoare
    sort(c.begin(), c.end(), [](number a, number b) {
        return a.value < b.value; });
    sort(d.begin(), d.end(), [](number a, number b) {
        return a.value > b.value; });

    // apelez functia de calculare a sumei maxime
    long sum_max = max_sum(a, b);
    int index = 0;
    // pentru fiecare mutare disponibila aleg elementul maxim din c si minim
    // din d si fac swap in a si b
    for (int swaps = 0; swaps < moves; swaps++) {
        int min_elem_index = c[index].og_index;
        int max_elem_index = d[index].og_index;

        // daca elementul maxim din c este mai mic decat cel minim din d
        // atunci ma opresc
        if (c[index].value > d[index].value)
            break;

        // calculez suma maxima dupa swap in mod eficient
        long temp = sum_max - max(a[min_elem_index], b[min_elem_index]) -
                max(a[max_elem_index], b[max_elem_index]);
        swap(a[min_elem_index], b[max_elem_index]);
        temp = temp + max(a[min_elem_index], b[min_elem_index]) +
                max(a[max_elem_index], b[max_elem_index]);
        // daca suma maxima dupa swap este mai mare decat cea initiala
        // atunci o actualizez
        if (temp > sum_max) {
            sum_max = temp;
        } else {
            break;
        }
        index++;
    }
    return sum_max;
}

