			f1[i][j] = (f0[i-1][i-j]) % mod;
	}

	return ((f0[x+y][x]) % mod + (f1[x+y][y]) % mod) % mod;
}

/* Compute the number of type 2 signals. */
int type2(int x, int y) {
	int i, j;

	int **f0 = (int **) calloc((x+y+1), sizeof(int *));
	int **f1 = (int **) calloc((x+y+1), sizeof(int *));

	for (i = 0; i < x+y+1; i++) {
		f0[i] = (int *) calloc((x+1), sizeof(int));
		f1[i] = (int *) calloc((y+1), sizeof(int));
	}

	/* Base steps */
	f0[0][0] = 0;
	f0[0][1] = 0;
	f0[0][2] = 0;
	f0[1][0] = 0;
	f0[1][1] = 1;
	f0[1][2] = 0;
	f0[2][0] = 0;
	f0[2][1] = 1;
	f0[2][2] = 1;

	f1[0][0] = 0;
	f1[0][1] = 0;
	f1[0][2] = 0;
	f1[1][0] = 0;
	f1[1][1] = 1;
	f1[1][2] = 0;
	f1[2][0] = 0;
	f1[2][1] = 1;
	f1[2][2] = 1;

	/* Fill arrays */
	for (i = 3; i <= x + y; i++) {
		for (j = 1; j <= x; j++)
			f0[i][j] = ((f0[i-1][j-1]) % mod + (f1[i-1][i-j]) % mod) % mod;

		for (j = 1; j <= y; j++)
			f1[i][j] = ((f0[i-1][i-j]) % mod + (f0[i-2][i-j]) % mod) % mod;
	}

	return ((f0[x+y][x]) % mod + (f1[x+y][y]) % mod) % mod;
}

