class Semnale {

	static int sig_type, x, y;
	static final int  mod = 1000000007;

	Semnale(){}

	static int type1() {
		//TODO Compute the number of type 1 signals.

		/*
		dp[k][i][j] = Number of bit strings with i bits overall,
					  j bits set to 0 and last bit set to k.
			- k = last bit value {0/1};
			- i = number of bits {1, ..., x + y};
			- j = number of bits set to 0 {0, ..., min(i, x)}.
		 */

		int[][][] dp = new int[2][x + y + 1][x + 1];

		/*
		Base case (for bit strings with only one bit - 0, 1):
		(Explanation: I go one step back during the recursion)
		 */
		dp[0][1][1] = 1; // 0
		dp[1][1][0] = 1; // 1

		/*
		General case (for bit strings longer than one):
		 */
		for (int i = 2; i <= x + y; i++) {

			/*
			Number of bits set to 0 (j) can't be higher than the total number of bits (i),
			therefore I can't use j <= x, as there are cases when i is lower than x.
			 */
			for (int j = 1; j <= Math.min(i, x); j++) {

				/*
				If I'm adding a bit set to 0, I have to look back at past solutions that
				meet the following criteria:
					- end in 0/1 (hence the sum of two past solutions);
					- are shorter with a bit (i - 1);
					- are shorter with a bit set to 0 (j - 1).
				 */
				dp[0][i][j] = (dp[0][i - 1][j - 1] + dp[1][i - 1][j - 1]) % mod;

				/*
				If I'm adding a bit set to 1, I have to look back at past solutions that
				meet the following criteria:
					- end in 0;
					- are shorter with a bit (i - 1);
					- have the same number of bits set to 0 (j).
				 */
				dp[1][i][j] = dp[0][i - 1][j];
			}
		}

		/*
		The final solution is the number of bit strings that end in 0 or 1,
		therefore I add these two partial solutions.
		 */
		return (dp[0][x + y][x] + dp[1][x + y][x]) % mod;
	}

	static int type2() {
		//TODO Compute the number of type 2 signals.

		/*
		Same strategy as in type1() method, so I'll point out only the differences.
		 */

		int[][][] dp = new int[2][x + y + 1][x + 1];

		/*
		Base case (for bit strings with one or two bits - 0, 1, 00, 01, 10, 11):
		(Explanation: I go two steps back during the recursion)
		 */
		dp[0][1][1] = 1; // 0
		dp[1][1][0] = 1; // 1
		dp[0][2][2] = 1; // 00
		dp[1][2][1] = 1; // 01
		dp[0][2][1] = 1; // 10
		dp[1][2][0] = 1; // 11

		/*
		General case (for bit strings longer than two):
		 */
		for (int i = 3; i <= x + y; i++) {

			for (int j = 1; j <= Math.min(i, x); j++) {

				dp[0][i][j] = (dp[0][i - 1][j - 1] + dp[1][i - 1][j - 1]) % mod;

				/*
				If I'm adding a bit set to 1, I have to look back at past solutions that
				meet the following criteria:
					- end in 0;
					- are shorter with a bit or two (i - 1) / (i - 2)
					  (hence the sum of two past solutions);
					- have the same number of bits set to 0 (j).
				 */
				dp[1][i][j] = (dp[0][i - 1][j] + dp[0][i - 2][j]) % mod;
			}
		}

		return (dp[0][x + y][x] + dp[1][x + y][x]) % mod;
	}

