        #include <bits/stdc++.h>
using namespace std;

static constexpr int NMAX = (int)1e5 + 5;
static constexpr int INF = 1e9;

int n, m;
vector<int> adj[NMAX];

vector<int> parent;
vector<int> found;
vector<int> low_link;
stack<int> nodes_stack;
vector<bool> in_stack;

vector<vector<int>> all_sccs;
unordered_map<int, int> scc_index;
int nr_scc = 0;

/**
 * Tarjan pentru a determina toate SCC
**/

void dfs(int node, int& timestamp, vector<vector<int>>& all_sccs) {
        found[node] = ++timestamp;
        low_link[node] = found[node];
        nodes_stack.push(node);
        in_stack[node] = true;
        for (auto neigh : adj[node]) {
            if (parent[neigh] != -1) {
                if (in_stack[neigh]) {
                    low_link[node] = min(low_link[node], found[neigh]);
                }
                continue;
            }
            parent[neigh] = node;
            dfs(neigh, timestamp, all_sccs);
            low_link[node] = min(low_link[node], low_link[neigh]);
        }
        if (low_link[node] == found[node]) {
            vector<int> scc;
            nr_scc ++;
            do {
                auto x = nodes_stack.top();
                nodes_stack.pop();
                in_stack[x] = false;

                scc.push_back(x);
                scc_index[x] = nr_scc;
            } while (scc.back() != node);
            all_sccs.push_back(scc);
        }
    }

vector<vector<int>> tarjan_scc() {
    parent = vector<int>(n + 1, -1);
    found = vector<int>(n + 1, -1);
    low_link = vector<int>(n + 1, -1);
    in_stack = vector<bool>(n + 1, false);
    int timestamp = 0;
    for (int node = 1; node <= n; ++node) {
        if (parent[node] == -1) {
            parent[node] = node;
            dfs(node, timestamp, all_sccs);
        }
    }
    return all_sccs;
}

vector<vector<int>> get_result() {
    return tarjan_scc();
}

/**
 * Parcurgerea nodurilor pentru a vedea daca se pot gasi
 * drumuri intre 2 componente conexe diferite astfel incat
 * numarul de muchii care trebuie adaugate sa fie minim
**/

int get_number(int source) {
    int nr = 0;
    vector<bool> used(all_sccs.size(), false);
    used[scc_index[source]] = true;
    for (int i = 1; i <= n; i++) {
        for (auto neigh : adj[i]) {
            if (scc_index[neigh] != scc_index[i] &&
                used[scc_index[neigh]] == false) {
                used[scc_index[neigh]] = true;
                nr++;
            }
        }
    }
    int sol = all_sccs.size() - nr;
    sol--;
    return sol;
}
int main() {
    ifstream fin("ferate.in");
    ofstream fout("ferate.out");
    int s;
    fin >> n >> m >> s;
    for (int i = 1, x, y; i <= m; i++) {
        fin >> x >> y;
        adj[x].push_back(y);
    }
    get_result();

    int sol = get_number(s);
    fout << sol;
    return 0;
}

