void DFS(int node, vector<int> adj[], vector<int> order[]) {
    for (auto next : adj[node]) {
        // Recursively call DFS on the neighbour
        DFS(next, adj, order);

        // Upon return, update the order array of the current node
        // by adding the neighbour and appending its order array
        order[node].push_back(next);
        order[node].insert(order[node].end(), order[next].begin(),
                           order[next].end());
    }
}

int main() {
    int N, Q;
    fin >> N >> Q;

    vector<int> adj[N + 1];
    vector<int> order[N + 1];

    // Create the adjacency lists
    for (int i = 2; i <= N; i++) {
        int j;
        fin >> j;
        adj[j].push_back(i);
    }

    // Perform DFS while computing the traversal order
    // for each node (all the nodes that ar visited during)
    // DFS starting from it)
    DFS(1, adj, order);

    // Read queries
    while (Q--) {
        int node, pos;
        fin >> node >> pos;

        // Provide requested node, if it exists
        if (order[node].size() >= pos)
            fout << order[node][pos - 1] << "\n";
        else
            fout << "-1\n";
    }
}

