	public static int topSortColour(String current_colour, Queue<Integer> redq,
									Queue<Integer> blueq, ArrayList<Integer>[] adj,
									int[] indegree) {
		Queue<Integer> que = new LinkedList<Integer>();
		if (current_colour.equals(new String("red"))) {
			que = redq;
		} else {
			que = blueq;
		}

		int switches = -1;
		while (!que.isEmpty()) {
			int node = que.poll();
			for (Integer child : adj[node]) {
				indegree[child]--;
				if (indegree[child] == 0) {
					if (colour[child] == 1) {
						blueq.add(child);
					} else {
						redq.add(child);
					}
				}
			}

			//coada curenta a ajuns sa fie goala:
			//vf ce culoare a fost si mut coada pe cealalta culoare
			if (que.isEmpty()) {
				if (current_colour.equals(new String("red"))) {
					current_colour = "blue";
					switches++;
					que = blueq;
				} else {
					current_colour = "red";
					switches++;
					que = redq;
				}
			}
		}
		return switches;
	}

