        #include <iostream>
#include <fstream>
#include <vector>
#include <stack>
#include <algorithm>

using namespace std;

const int MAXN = 1e5+5;

vector<int> task_order[MAXN];
vector<int> data_set(MAXN);
vector<int> in_degree(MAXN);
stack<int> stack1, stack2;
int N;

int solve(int current_stack) {
    int switches = 0, i = 0, current_task = 0;
    // copii pentru cazurile in care trebuie sa rezolvam de 2 ori
    stack<int> stack1_copy = stack1, stack2_copy = stack2;
    vector<int> in_degree_copy = in_degree;
    while (i < N) {
        if (current_stack == 1 && !stack1_copy.empty()) {
            current_task = stack1_copy.top(); stack1_copy.pop(); i++;

        } else if (current_stack == 2 && !stack2_copy.empty()) {
            current_task = stack2_copy.top(); stack2_copy.pop(); i++;
        }

        current_stack = data_set[current_task];
        // stergere nod curent din graf si actualizare in_degree
        // daca in_degree = 0, adaugam nodul in stiva corespunzatoare
        for (auto it : task_order[current_task]) {
            in_degree_copy[it]--;
            if (in_degree_copy[it] == 0) {
                if (data_set[it] == 1) {
                    stack1_copy.push(it);
                } else {
                    stack2_copy.push(it);
                }
            }
        }

        // daca stiva curenta este acum goala, facem context switch
        // si trecem pe cealalta stiva
        if (current_stack == 1 && stack1_copy.empty() && i < N) {
            current_stack = 2;
            switches++;
        } else if (current_stack == 2 && stack2_copy.empty() && i<N) {
            current_stack = 1;
            switches++;
        }
    }
    return switches;
}

int main() {
    ifstream fin("supercomputer.in");
    ofstream fout("supercomputer.out");

    int M;
    fin >> N >> M;
    for (int i = 1; i <= N; ++i) {
        fin >> data_set[i];
    }

    for (int i = 0; i < M; ++i) {
        int u, v;
        fin >> u >> v;
        task_order[u].push_back(v);
        in_degree[v]++;
    }

    // adaugam initial in stiva corespunzatoare nodurile cu in_degree = 0
    for (int i = 1; i <= N; ++i) {
        if (in_degree[i] == 0) {
            if (data_set[i] == 1)
                stack1.push(i);
            else
                stack2.push(i);
        }
    }

    if (!stack1.empty() && stack2.empty()) {
        fout  << solve(1);
    } else if (!stack2.empty() && stack1.empty()) {
        fout << solve(2);
    } else if (!stack1.empty() && !stack2.empty()) {
        int result1 = solve(1);
        int result2 = solve(2);
        fout << min(result1, result2);
    }

    fout.close();
    return 0;
}

