		List<Pair>[] adj = new ArrayList[n + 1];
		special = new ArrayList[n + 1];
		for (int i = 0; i <= n; i++) {
			adj[i] = new ArrayList<>();
			special[i] = new ArrayList<>();
		}

		for (int i = 0; i < m; i++) {
			int x = scanner.nextInt();
			int y = scanner.nextInt();
			int c = scanner.nextInt();

			adj[x].add(new Pair(y, c));
			adj[y].add(new Pair(x, c));
		}

		Set<Integer> numbers = new HashSet<>();

		for (int i = 0; i < k; i++) {
			int x = scanner.nextInt();
			int y = scanner.nextInt();
			int c = scanner.nextInt();

			special[x].add(new Pair(y, c));
			special[y].add(new Pair(x, c));

			numbers.add(c);
		}

		int lcm = 1;
		for (Integer number : numbers) {
			lcm = lcm(lcm, number);
		}

		CMMMC = lcm;

