        #include <iostream>
#include <fstream>
#include <vector>
#include <iomanip>

using namespace std;

long long getSum(const vector<long long> &vec) {
    long long sum = 0;
    for (auto val : vec) {
        sum += val;
    }
    return sum;
}

bool check(const vector<long long> &a, const vector<long long> &b) {
    /* Verific egalitatea sumelor celor 2 siruri pentru a ma
    asigura ca pot gasi o solutie. */
    return getSum(a) == getSum(b);
}

int solve(vector<long long> &a, vector<long long> &b) {
    int count = 0;

    while (!a.empty() || !b.empty()) {
        if (a[a.size() - 1] == b[b.size() - 1]) {
            /* Daca am 2 elemente egale la final in ambii
            vectori trec mai departe deoarece pasul e corect. */
            a.pop_back();
            b.pop_back();
            count ++;
            continue;
        }

        if (a.size() > 1 && a[a.size() - 1] < b[b.size() - 1]) {
            /* Daca pe ultima pozitie in a[] am un element mai
            mic decat cel din b[] de la aceeasi pozitie atunci
            insumez acea valoare din a[] cu cea de la indexul anterior. */
            a[a.size() - 2] += a[a.size() - 1];
            a.pop_back();
            continue;
        }

        if (b.size() > 1 && a[a.size() - 1] > b[b.size() - 1]) {
            /* Daca pe ultima pozitie in b[] am un element mai
            mic decat cel din a[] de la aceeasi pozitie atunci
            insumez acea valoare din b[] cu cea de la indexul anterior. */
            b[b.size() - 2] += b[b.size() - 1];
            b.pop_back();
            continue;
        }

        return -1;
    }

    return count;
}

int main() {
    ifstream fin("compresie.in");
    ofstream fout("compresie.out");

    int n, m;

    fin >> n;  // Dimensiunea a[].
    vector<long long> a(n);

    for (int i = 0; i < n; i++) {
        fin >> a[i];
    }

    fin >> m;  // Dimensiunea b[].
    vector<long long> b(m);

    for (int i = 0; i < m; i++) {
        fin >> b[i];
    }

    // Verific daca conditia poate fi vreodata realizata.
    if (n == 0 || m == 0 || !check(a, b)) {
        fout << -1 << endl;
    } else {
        int result = solve(a, b);
        fout << fixed << setprecision(1) << result << endl;
    }

    return 0;
}

