/* Function that returns a vector with the unique characters
    from the vector of strings*/
std::vector<char> uniqueChars(const std::vector<std::string>& input) {
    std::vector<char> uniqueCharsVec;
    bool check;

    for (const std::string& str : input) {
        for (char c : str) {
            check = false;
            for (char uniqueChar : uniqueCharsVec) {
                if (c == uniqueChar) {
                    check = true;
                }
            }
            if (!check) {
                uniqueCharsVec.push_back(c);
            }
        }
    }
    return uniqueCharsVec;
}

/* Getting the cost of a word as target_letter_count - other_letter_count*/
int get_cost(const std::string curr_word, char c) {
    int tmp_char_count = std::count(curr_word.begin(), curr_word.end(), c);
    return 2 * tmp_char_count - curr_word.size();
}

int rucsac(int n, int W, std::vector<int> &w, std::vector<int> &p) {
    // dp este o matrice de dimensiune (n + 1) x (W + 1)
    // pentru că folosim dp[0][*] pentru mulțimea vidă
    // dp[*][0] pentru situația în care ghiozdanul are capacitate 0
    std::vector< std::vector<int> > dp(n + 1, std::vector<int>(W + 1, 0));

    // cazul de bază
    for (int cap = 0; cap <= W; ++cap) {
        dp[0][cap] = 0;
    }

    // cazul general
    for (int i = 1; i <= n; ++i) {
        for (int cap = 0; cap <= W; ++cap) {
            // nu folosesc obiectul i => e soluția de la pasul i - 1
            dp[i][cap] = dp[i-1][cap];

            // folosesc obiectul i, deci trebuie să rezerv w[i] unități în ruc
            // înseamnă ca înainte trebuie să ocup maxim cap - w[i] unități
            if (cap - w[i - 1] > 0) {
                int sol_aux = dp[i-1][cap - w[i - 1]] + p[i - 1];

                dp[i][cap] = std::max(dp[i][cap], sol_aux);
            }
        }
    }

    return dp[n][W];
}


