    std::ifstream fin("criptat.in");
    std::ofstream fout("criptat.out");

    int n;
    fin >> n;
    std::vector<std::string> words(n);

    for (int i = 0; i < n; i++) {
        fin >> words[i];
    }

    std::vector<char> uniqueCharsVec = uniqueChars(words);
    std::vector<int> answers;

    for (char c : uniqueCharsVec) {
        int final_length = 0;
        int final_cost = 0;

        std::vector<int> cost;
        std::vector<int> word_length;

        for (std::string word : words) {
            int tmp_cost = get_cost(word, c);

            /* If the word has a pozitive cost it is added to solution*/
            if (tmp_cost >= 0) {
                final_length += word.size();
                final_cost += tmp_cost;

            /* If the word has a negative cost
            it is added to the backpack problem*/
            } else {
                cost.push_back(0 - tmp_cost);
                word_length.push_back(word.size());
            }
        }

        /* Adding the answer from the backpack problem to the final length*/
        final_length += rucsac(cost.size(), final_cost, cost, word_length);

        answers.push_back(final_length);
    }

    int max = 0;

    /* Getting the maximum length from the answers*/
    for (int i : answers) {
        if (i > max) {
            max = i;
        }
    }

    fout << max << "\n";

    return 0;
}

