// function that removes duplicates from a sorted vector
vector<unsigned int> remove_duplicates(vector<unsigned int> merged) {
	vector<unsigned int> new_merged;

	for (unsigned long int i = 0; i < merged.size(); i++) {
		if (i == 0 || merged[i] != merged[i - 1]) {
