		return iter.hasNext() ? iter.next() : Double.POSITIVE_INFINITY;
	}

	private static int getMinIndex(double[] values) {
		int minIndex = 0;

		for (int i = 1; i < values.length; i++) {
			if (values[i] < values[minIndex]) {
				minIndex = i;
			}
		}

		return minIndex;
	}

	private static List<Double> getUpdatedPrices(List<Iterator<Double>> pricesBack, int k) {
		List<Double> result = new ArrayList<>(k);

		double[] prev = new double[pricesBack.size()];
		for (int i = 0; i < pricesBack.size(); i++) {
			prev[i] = getOrInf(pricesBack.get(i));
		}

		double prevResult = Double.NaN;
		for (int i = 0; i < k; i++) {
			int minIndex = getMinIndex(prev);
			if (Double.isInfinite(prev[minIndex])) {
