		}

		int prevPrice = prices.next();
		List<Double> prices1Back = new ArrayList<>();
		prices1Back.add(saleFull(prevPrice, sndPrevPrice, price));
		prices1Back.add(price + saleHalf(sndPrevPrice, prevPrice));
		int finalPrevPrice = prevPrice;
		prices2Back.stream().map(x -> x + finalPrevPrice).forEach(prices1Back::add);
		prices1Back.sort(Comparator.naturalOrder());

		while (prices.hasNext()) {
			final int priceB = prices.next();
			price = priceB;
			double halfSale = saleHalf(price, prevPrice);
			double fullSale = saleFull(price, prevPrice, sndPrevPrice);

			List<Double> newPrices = getUpdatedPrices(
				List.of(prices3Back.stream().map(x -> x + fullSale).iterator(),
					prices2Back.stream().map(x -> x + halfSale).iterator(),
					prices1Back.stream().map(x -> x + priceB).iterator()), k);

			prices3Back = prices2Back;
			prices2Back = prices1Back;
			prices1Back = newPrices;
			sndPrevPrice = prevPrice;
			prevPrice = price;
		}

		return getKthValue(prices1Back, k);
	}

	private static void writeResult(double result) throws IOException {
		try (FileWriter fileWriter = new FileWriter("oferta.out")) {
			fileWriter.write(Double.toString(result));
		}
	}

	public static void main(String[] args) throws IOException {
		try (FileReader fileReader = new FileReader("oferta.in")) {
			BufferedReader bufferedReader = new BufferedReader(fileReader);

			String[] firstLine = bufferedReader.readLine().split(" ");
			String[] secondLine = bufferedReader.readLine().split(" ");
			Iterator<Integer> prices = Arrays.stream(secondLine).map(Integer::parseInt).iterator();

			bufferedReader.close();

			assert firstLine.length == 2;
			int n = Integer.parseInt(firstLine[0]);
			int k = Integer.parseInt(firstLine[1]);

			writeResult(computeResult(prices, n, k));
		}
	}
}

