const long long INF = numeric_limits<long long>::max();
// algoritmul Dijkstra pentru a calcula cea a scurta distanta
vector<long long> dijkstra(int source, vector<vector<pair
                                        <long long, int>>>& graph, int n) {
    // initializarea vectorului cu valoarea infinit
    vector<long long> d(n + 1, INF);
    // initializarea vectorului de vizitat cu false
    vector<bool> visited(n + 1, false);
    // coada de prioritati pentru a mentine nodurile in ordine
    priority_queue<pair<long long, int>, vector<pair<long long, int>>,
                    greater<pair<long long, int>>> pq;
    // initializarea distantei de la sursa la sursa cu 0
    d[source] = 0;
    pq.push({0, source});
    // cat timp coada nu este goala se va extrage nodul cu distanta minima
    while (!pq.empty()) {
        int node = pq.top().second;
        pq.pop();
        // daca nodul a fost vizitat se va trece la urmatorul nod
        if (visited[node])
            continue;
        // se marcheaza nodul ca vizitat
        visited[node] = true;

        for (auto& edge : graph[node]) {
            int neigh = edge.second;
            // se calculeaza costul
            long long cost = edge.first;
          /*daca noua distanta este mai mica decat distanta curenta, atunci
          se va actualiza distanta pentru vecin si se adauga in coada de 
          prioritati noua distanta*/
            if (d[node] + cost < d[neigh]) {
                d[neigh] = d[node] + cost;
                pq.push({d[neigh], neigh});
            }
        }
    }
    return d;
}

int main() {
    ifstream fin("drumuri.in");
    ofstream fout("drumuri.out");
    int N, M;
    fin >> N >> M;

    vector<vector<pair<long long, int>>> graph(N + 1);
    vector<vector<pair<long long, int>>> rev_graph(N + 1);
    int a, b;
    long long c;

    for (int i = 0; i < M; ++i) {
        fin >> a >> b >> c;
        // graful original
        graph[a].push_back({c, b});
        // inversez graful pentru a calcula distanta de la z la oricare alt nod
        rev_graph[b].push_back({c, a});
    }

    int x, y, z;
    fin >> x >> y >> z;

    // distanta de la z la oricare alt nod
    vector<long long> distFromZ = dijkstra(z, rev_graph, N);

    // distanta cea mai scurta de la x la oricare alt nod
    vector<long long> distFromX = dijkstra(x, graph, N);
    // distanta cea mai scurta de la y la oricare alt nod
    vector<long long> distFromY = dijkstra(y, graph, N);

    // calculez distanta minima de la x la y trecand prin z
    long long result = INF;
    for (int i = 1; i <= N; i++) {
        if (distFromX[i] != INF && distFromY[i] != INF && distFromZ[i] != INF) {
            result = min(result, distFromX[i] + distFromY[i] + distFromZ[i]);
        }
    }

    fout << result << endl;

    return 0;
}

