using namespace std;
#define MAX_NODES 100001

// Dijkstra algoritm to find minimal distance
vector<long long> dijkstra(int N, int source,
            vector<pair<int, int>> graph[MAX_NODES]) {
    vector<long long> dist(N + 1, LLONG_MAX);
    vector<int> parent(N + 1, -1);
    dist[source] = 0;

    set<pair<long long, int>> pq;

    pq.insert({dist[source], source});

    while (!pq.empty()) {
        auto top = pq.begin();
        const auto [_, node] = *top;
        pq.erase(top);

        for (const auto& [neigh, w] : graph[node]) {
            if (dist[node] + w < dist[neigh]) {
                pq.erase({dist[neigh], neigh});
                dist[neigh] = dist[node] + w;
                parent[neigh] = node;
                pq.insert({dist[neigh], neigh});
            }
        }
    }


    for (int i = 1; i <= N; i++) {
        if (dist[i] == LLONG_MAX) {
            dist[i] = -1;
        }
    }

    return dist;
}


