    vector<pair<int, int>> transpose_graph[MAX_NODES];

    // Create the graph and the transpose of the graph
    for (i = 1; i <= M; i++) {
        fin >> a >> b >> c;
        graph[a].push_back({b, c});
        transpose_graph[b].push_back({a, c});
    }
    fin >> x >> y >> z;

    // Calculate the distance of the shortest path for each node
    vector<long long> distances = dijkstra(N, x, graph);
    vector<long long> distances2 = dijkstra(N, y, graph);
    vector<long long> distances3 = dijkstra(N, z, transpose_graph);

    // If the path exist find the minimum distance between the 3 shortest paths
    long long min_dist = LLONG_MAX;
    for (i = 1; i <= N; i++) {
        if (distances[i] != -1 && distances2[i] != -1 && distances3[i] != -1) {
            min_dist = min(min_dist,
            distances[i] + distances2[i] + distances3[i]);
        }
    }

