        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Collections;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;
import java.util.Scanner;


public class Numarare {

	public final String inputFile = "numarare.in";
	public final String outputFile = "numarare.out";

	int N, M;
	int indexValue;
	public static int ZERO = 0;
	public static long ZERO_L = 0L;
	public static long ONE_L = 1L;
	public static long mod_val = 1000000007;
	Queue<Integer> queue = new LinkedList<>();
	List<List<Integer>> routes = new ArrayList<>();
	List<List<Integer>> routes2 = new ArrayList<>();
	List<List<Integer>> InverseRoutes = new ArrayList<>();
	List<List<Integer>> InverseRoutes2 = new ArrayList<>();

	List<Long> values = new ArrayList<>();

	List<Integer> degree = new ArrayList<>();
	int index;

	public void solve2() {
		readInput();
		writeOutput(getResult());

	}

	private void readInput() {
		try {
			Scanner sc = new Scanner(new File(inputFile));
			N = sc.nextInt();
			M = sc.nextInt();
			routes = new ArrayList<>(N + 1);
			routes2 = new ArrayList<>(N + 1);
			InverseRoutes = new ArrayList<>(N + 1);
			InverseRoutes2 = new ArrayList<>(N + 1);

			degree = new ArrayList<>(Collections.nCopies(N + 1, ZERO));
			values = new ArrayList<>(Collections.nCopies(N + 1, ZERO_L));
			index = N - 1;

			for (int i = 1; i <= M; i++) {
				routes.add(new ArrayList<>());
				routes2.add(new ArrayList<>());
				InverseRoutes.add(new ArrayList<>());
				InverseRoutes2.add(new ArrayList<>());

			}
			for (int i = 1; i <= M; i++) {
				/// node-ul normala
				int node = sc.nextInt();
				/// neigh
				int neigh = sc.nextInt();
				///gradul normal
				degree.set(neigh, degree.get(neigh) + 1);
				routes.get(node).add(neigh);
				///muchia normala
				InverseRoutes.get(neigh).add(node);

			}

			for (int i = 1; i <= M; i++) {
				/// muchia inversata adica neigh
				int invertedNode = sc.nextInt();
				/// nodul normal
				int neighRev = sc.nextInt();
				routes2.get(invertedNode).add(neighRev);
				/// muchia inversata
				InverseRoutes2.get(neighRev).add(invertedNode);
			}

			for (int i = 1; i <= N; i++) {
				///daca sunt frunze cu gradul normal 0 la adaugam in coada
				/// care ne vor fi folositoare apoi pentru sortarea topologica
				/// cand trebuie sa adaugam nodurile nefolosite de alte noduri
				/// de unde pornim spre alte noduri cu grad mai mare,
				/// spre ale adauga mai tarziu daca le facem de grad zero cat mai
				/// repede
				///adica parcurgem toti parintii nodului mai repede

				if (degree.get(i) == ZERO) {
					queue.add(i);
				}

			}
			/// avem un singur lant elementar comun care porneste de la 1 deocamdata
			values.set(1, ONE_L);

		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void writeOutput(long result) {
		try {
			PrintWriter pw = new PrintWriter(new File(outputFile));
			pw.print(result);
			pw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	void bfs(List<Integer> topo_sort) {


		while (!queue.isEmpty()) {
			int current = queue.poll();
			topo_sort.add(current);
			index++;
			for (int i : routes.get(current)) {
				/// scadem gradul nodului daca am trecut prin muchii parinte cu nodul sau copil
				degree.set(i, degree.get(i) - 1);
				if (degree.get(i) == ZERO && routes2.get(current).contains(i)) {
					///asta sa intampla doar daca
					///exista muchia si in graful celalalt
					queue.add(i);
				}

			}

		}

	}


	void find_commmon_chain(List<Integer> topo_sort) {
		int i = 1;
		while (i < N && topo_sort.get(i) != ZERO) {
			for (int j : InverseRoutes.get(topo_sort.get(i))) {
				if (InverseRoutes2.get(topo_sort.get(i)).contains(j)) {
					long value = values.get(topo_sort.get(i)) + values.get(j);
					/// facem asta cu modulo pentru a evita valorile
					/// foarte mari
					values.set(topo_sort.get(i), value % mod_val);
				}
			}
			i++;
		}

	}

	private long getResult() {

		List<Integer> topo_sort = new ArrayList<>();
		indexValue = N;
		/// facem sortarea topologica comuna pentru ambele grafuri
		/// este mai eficienta decat sa facem pentru doua dintre ele
		bfs(topo_sort);
		///dupa gasim numarul de lanturi elementare comune
		find_commmon_chain(topo_sort);

		return values.get(N);

	}


	public static void main(String[] args) {
		new Numarare().solve2();
	}


}

